var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"......니! 리타 언니! 일어나세요! 어서요!","JPN":"……ね……ちゃん！　リタお姉ちゃん！　目を覚ましてください！　はやく！","ENG":"—ta! Rita! Wake up! Come on!","TWN":"……姐！麗塔姐姐！快醒醒！快！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"죽으면 안 돼요! 제발요!","JPN":"死なないでください！　お願い！","ENG":"Don't die on me! Please!","TWN":"不能死！求你了！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"으음......","JPN":"ううん……","ENG":"Hngh...","TWN":"唔……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"너는...... 꼬맹이?","JPN":"お前は……ガキ？","ENG":"You... Kid?","TWN":"你是……小鬼？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"다행이다......! 언니가 이대로 죽을까 봐 엄청 걱정했어요!","JPN":"よかった……！　このまま死んじゃうんじゃないかと心配したんです！","ENG":"Thank goodness! I was worried sick you might die on me!","TWN":"真是太好了……！我還擔心姐姐就這麼死了呢！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"악몽이었나......? 그렇게 생생했는데?","JPN":"悪夢だったのか……？　結構リアルだったが。","ENG":"Was that a nightmare? But it was so vivid!","TWN":"難道是個噩夢……？太真實了？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니, 아픈 데는 없어요? 오메르타는 단단하니까 어디 부딪쳐서 다쳤을지도 몰라요.","JPN":"リタお姉ちゃん、具合はどうですか？　オメルタは硬いから打ちどころが悪くて怪我をしているかもしれません。","ENG":"Are you hurt anywhere, Rita? Given how hard Omerta is, you might have hurt yourself bumping into the ground.","TWN":"姐姐，有沒有受傷？奧梅爾塔太堅硬，說不定撞到哪裡受傷了呢。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"몸에 힘이 잘 안 들어가긴 하지만...... 다친 곳은 없어.","JPN":"体に力は入らないけど……怪我はない。","ENG":"I'm feeling a bit lethargic... but otherwise I'm fine.","TWN":"身體有點使不上力氣……但沒受傷。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그보다, 유적에서 찾았던 수정은?","JPN":"それより、遺跡で見つけた水晶は？","ENG":"More importantly, what did you do with the crystal from the ruins?","TWN":"話說回來，在遺跡中拿的水晶呢？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"아, 네! 가방에 잘 넣어 뒀어요!","JPN":"あ、はい！　カバンの中にあります！","ENG":"Oh! I kept it safe in a bag!","TWN":"啊，是！我把它放進背包裡了！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이리 줘 봐.","JPN":"こっちによこせ。","ENG":"Bring it to me.","TWN":"給我。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"수정을 손에 넣은 자에게 <color=#ffd34c>완전한 존재</color>로 거듭날 기회를 주고자 했건만......","JPN":"水晶を手に入れた者に<color=#ffd34c>完全なる存在</color>へと生まれ変わる機会を与えようとしたが……","ENG":"I sought to grant the chance to be reborn as <color=#ffd34c>a perfect being</color> to the one who found the crystal...","TWN":"本想給拿到水晶的人一個成為<color=#ffd34c>完整存在</color>的機會。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그 아이는 내 목소리에 귀를 기울이지 않더구나.","JPN":"あの小娘は私の声に耳を貸さなかった。","ENG":"But the child did not heed my voice.","TWN":"但那個孩子聽不到我的聲音。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"리, 리타 언니! 수정이 깨졌어요! 어떡해요?!","JPN":"リ、リタお姉ちゃん！　水晶が割れちゃいました！　どうしましょう！？","ENG":"R-Rita! The crystal broke! What are we going to do?!","TWN":"麗、麗塔姐姐！你把水晶打碎了！怎麼辦？！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"저런 뭔지도 모를 기분 나쁜 물건은 없애 버리는 편이 더 나아.","JPN":"あんな得体の知れない気味が悪い物は無い方がいい。","ENG":"We're better off without that creepy thing. Who knows what it really is.","TWN":"那種莫名讓人心情很差的東西丟掉反而更好。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"하지만...... 저희한테는 저 수정이 마지막으로 남은 건데......","JPN":"でも……私たちにはあの水晶しか残ってないのに……","ENG":"But... That's all we've got now...","TWN":"但是……對我們來說剩下來的就只有那個水晶……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아무렇지 않은 척 그만하고 말해 봐, 꼬맹이.","JPN":"平気なふりをするのはいい加減やめて、そろそろ話せ。","ENG":"Stop pretending everything else is okay and fess up, kid.","TWN":"別逞強了，說吧，小鬼。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"내가 정신을 잃은 동안 무슨 일이 있었는지.","JPN":"私が気を失っている間、何があった。","ENG":"What happened with you while I was knocked out?","TWN":"我失去意識的這段時間發生了什麼事。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"네? 저, 전 별일 없었어요! 정말로요!","JPN":"え？　い、いや別に何もなかったですよ！　本当です！","ENG":"Huh? N-nothing, really! I swear!","TWN":"嗯？我、我沒事！真的！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"넌 거짓말이랑 안 어울려. 대답만 들어도 다 알 수 있어.","JPN":"お前は嘘が下手だ。もうバレているんだよ。","ENG":"You're a terrible liar. I can tell just by the tone of your voice.","TWN":"你不擅長說謊。聽你的回答就知道。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그게......","JPN":"それが……","ENG":"Well...","TWN":"那個……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"인간이 침식체로 변이하는 광경을 목격했습니다.","JPN":"人間が侵食体に変異する光景を目撃しました。","ENG":"She witnessed a human transforming into a C.O.","TWN":"她親眼看到了人類變異為侵蝕體的樣子。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_UNIT_AIR_DRONE_START"},{"id":"L39_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"그러니 목소리를 낮춰 주십시오. 밖에 돌아다니는 침식체들에게 발각될 수 있습니다.","JPN":"だから声を抑えてください。外の侵食体に発見される可能性があります。","ENG":"So please keep your voice down. You could give our location away to the C.O.s roaming outside.","TWN":"所以小聲些。別被外面的侵蝕體發現了。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"대표님!","JPN":"代表！","ENG":"Boss!","TWN":"BOSS！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"호라이즌? 어디 처박혀 있다가 이제 나타난 거야?","JPN":"ホライズン？　どこに隠れていやがったんだ！","ENG":"Horizon? Where have you been hiding your metal butt this whole time?","TWN":"地平線？你躲到哪去了，為什麼到現在才出現？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"감사부터 하십시오. 제가 없었으면 둘 다 숨을 곳도 못 찾고 객사했을 겁니다.","JPN":"それがお礼の言葉ですか。私がいなかったら二人とも隠れる場所すら見つからず客死したはずです。","ENG":"You ought to thank me first. Both of you would have perished without me, let alone manage to hide here.","TWN":"你還是先感謝我吧。如果沒有我，你們兩個找不到地方藏身早已經客死他鄉了。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"그런데 왜 아까운 수정은 저렇게 박살을 냈습니까?","JPN":"ところで、どうしてあの水晶を壊したのですか？　もったいないことを。","ENG":"By the way, why did you shatter the crystal? It seemed valuable.","TWN":"但是那麼寶貝的水晶怎麼被打碎了？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"요약하면 광견병 걸린 흰둥이한테 덮쳐지는 꿈을 꾼 뒤, 불안한 마음에 고가의 자산을 폐기하기로 결정했다는 거군요.","JPN":"要するに狂犬病にかかった白い犬に襲われる夢をみた後、不安な気持ちで高価な物を廃棄することにしたということですね。","ENG":"So to summarize, you dreamt of being ravaged by a rabid albino and subsequently decided to discard a highly valuable Artifact because you grew anxious.","TWN":"簡單來說就是，在夢裡被得了狂犬病的小白攻擊後，你覺得很不安，所以決定把高價資產破壞。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"여긴 이면세계야. 살아남기도 급급한 마당에 자산 가치를 저울질 할 여유는 없어.","JPN":"ここは裏世界だ。生き延びることに必死なのに、資産を増やすことまで考える余裕はない。","ENG":"This is the Counterside. We can't afford to weigh the value of assets when we're busy just trying to survive.","TWN":"這裡是異界。在生死關頭可沒時間權衡資產價值。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그리고 사진 속에서 나타났던 그 그림자도 신경 쓰여.","JPN":"そして写真の中から出てきたシャドウも気になる。","ENG":"And the Shadow from the photo is bothering me too.","TWN":"還有從照片裡出來的那個暗影也讓我很不安。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"검증도 안 된 추론에 너무 예민한 반응이군요.","JPN":"検証もされていない推論なのに、とても敏感な反応ですね。","ENG":"You are responding rather sensitively to unconfirmed conjecture.","TWN":"你對未經過具體驗證的推論太敏感了。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"정말 미래의 모습을 보여 주는지, 아니면 괴물을 만드는 건지는 관심 없어. 이건 그냥 기분 문제야.","JPN":"本当に未来の姿を見せたのか、それとも怪物を作っただけなのかは興味ない。これはただ気分の問題だ。","ENG":"I couldn't care less if it really shows the future or just generates monsters. This is just how I feel.","TWN":"我不管她是來自未來還是怪物，這只是心情問題。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그렇지만...... 언니 말이 진짜면 그 여자 분은 왜 저를 노리는 걸까요?","JPN":"でも……それが事実ならその女性はなぜ私を狙っているんでしょう？","ENG":"But still... If what you said is true, why would that lady come after me?","TWN":"但是……如果姐姐說的是真的，那個女人為什麼盯上我？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"글쎄. 단순히 우리가 허둥대는 꼴을 보고 싶었을지도 모르지.","JPN":"さあな。単に我々がうろたえている姿が見たかっただけかもしれない。","ENG":"Who knows. Maybe she just wants to see us struggle.","TWN":"誰知道呢。也許只是想看看我們手忙腳亂的樣子。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아무튼 그렇게 됐으니 네 몸 간수나 잘 해.","JPN":"まあということで、お前は気を付けろ。","ENG":"Anyway, you'd better take care of yourself with all that's happened.","TWN":"既已如此，你一定要小心。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"몸 간수라면 리타도 신경 써야 하는 처지입니다.","JPN":"気を付けるべきなのはリタも同じです。","ENG":"Speak for yourself, Rita.","TWN":"麗塔你也是，照顧好自己。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"내가?","JPN":"私？","ENG":"Me?","TWN":"我？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"워치를 보십시오. 바늘이 0에 가까워져 있습니다.","JPN":"ウォッチを見てください。針が0に近いです。","ENG":"Look at your Watch. The hand is pointing almost at zero.","TWN":"看看你的能量環。指針快到0了。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"대시에게 듣기로는 지하에서부터 계속 교전을 겪었다고 하더군요.","JPN":"ダッシュの話だと、地下から交戦を続けてきたそうですね。","ENG":"Dash tells me you've been fighting your way through since when you were underground.","TWN":"聽黛西說，在地下開始你就不斷在戰鬥中。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"부상을 회복하는 과정에서 그나마 남아 있던 CRF도 상당량 소모된 것으로 보입니다.","JPN":"負傷を回復する過程で残っていたCRFも相当消費しているようです。","ENG":"It appears you've exhausted a considerable amount of your remaining CRF recovering from your wounds.","TWN":"看來在身體恢復的過程中，剩下的CRF也消耗了很多。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"이럴 줄 알았으면...... 그 때 유적에서 이터니움이라도 챙겨 올 걸 그랬나 봐요.","JPN":"こうなるとわかってたら……遺跡からエタニウムでも持ってくればよかったです。","ENG":"If I had known it would come to this... I would have brought some Eternium from the ruins.","TWN":"早知如此……那個時候應該在遺跡裡拿一些永恆之金出來的。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아니. 후회해 봤자 늦었어. 안에 있던 이터니움은 수송선에 실려 있을 테니까.","JPN":"いや、今更後悔しても無駄だ。中のエタニウムは輸送船に運んでいるはずだし。","ENG":"No. It's too late for that anyway. Any Eternium that was there is probably loaded on the ship now.","TWN":"不。後悔已經晚了。裡面的永恆之金應該被裝進了運輸船。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그 정도 양이라면 장물로 처리해도 한 몫 단단히 잡겠지.","JPN":"あれぐらいの量ならかなり儲かるんだろうな。","ENG":"That will fetch a fortune, even if you just fence it.","TWN":"那麼多永恆之金，即使以銷贓處理，也能狠狠撈一筆。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"......저, 언니.","JPN":"……あの、リタお姉ちゃん。","ENG":"Um... Rita?","TWN":"……那個，姐姐。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"죄송해요. 윌버 씨가 그런 사람인 줄도 모르고...... 제가 바보처럼 편을 드는 바람에......","JPN":"ごめんなさい。\\nウィルバーさんがあんな人だと気付かず……\\n私がバカみたいにあの人の味方をしたせいで……","ENG":"Sorry. I had no idea Wilbur would be such a jerk... It was so stupid of me to take his side...","TWN":"對不起。我不知道韋爾伯是那樣的人……我還像傻瓜一樣支持他……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"알면 그걸로 됐어. 비싼 수업료 치렀다고 생각해.","JPN":"自覚しているならいい。高い授業料を払ったってことにしておこう。","ENG":"Well, now you know. Consider it a very expensive lesson.","TWN":"現在知道就行了。就當是花錢買教訓吧。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"기회를 주기로 결정한 사람은 나야. 그러니 그 놈을 처리하는 것도 내가 해야지.","JPN":"チャンスを与えると決めたのは私だ。だからそいつを始末するのも私だ。","ENG":"I'm the one who made the decision to give him another chance. So it's my responsibility to deal with him now.","TWN":"決定給他機會的人是我。所以處理那個傢伙的事也應該由我來做。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"너무 걱정 마. 그 놈은 이 대가를 몇 배로 치르게 될 테니까.","JPN":"あんまり心配するな。あいつには数百倍にして対価を払ってもらうつもりだ。","ENG":"Don't worry. He'll pay for what he's done many times over.","TWN":"別擔心，那傢伙會為他的所作所為付出幾倍的代價。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......지금은 바깥에 있는 저것들한테서 어떻게 벗어날지부터 고민해 봐야겠지만.","JPN":"……とりあえず、外にいる奴らからどうやって逃げるか悩むべきだな。","ENG":"Although... I guess we should worry about what to do with those guys out there first.","TWN":"……現在要想的是怎麼擺脫外面那些傢伙。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_46"}]`);export{e as default};